mapper.delete:
DELETE FROM ai_classroom_portrait_keyword
WHERE classroom_id = #{classroomId}
  AND course_id = #{courseId}

mapper.select:
SELECT keyword_id as id,
       keyword_name as keywordName,
       import_level as importLevel,
       datavalue as dataValue,
       stu_datavalue as stuDataValue
FROM ai_classroom_portrait_keyword
WHERE classroom_id = #{classroomId}
  AND course_id = #{courseId}
  AND num = #{num}
